namespace sv_66c60f7ffa4d4112a468fbe69c050f4f.Services;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

@using sv_66c60f7ffa4d4112a468fbe69c050f4f.Services

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <span class="text-muted small">@Task.DueDate.ToString("MMM dd")</span>
        <div class="mt-2 d-flex gap-1">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft">← Move Left</button>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@using sv_66c60f7ffa4d4112a468fbe69c050f4f.Services

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body" style="min-height: 200px; overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="() => OnMoveLeft.InvokeAsync(task.Id)"
                          OnMoveRight="() => OnMoveRight.InvokeAsync(task.Id)" />
            }

            @if (showAddForm)
            {
                <AddTaskForm OnSave="HandleAddTask" OnCancel="() => showAddForm = false" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100 mt-2" @onclick="() => showAddForm = true">
                    + Add Task
                </button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
    [Parameter] public List<TaskItem> Tasks { get; set; } = [];
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<int> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<int> OnMoveRight { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnAddTask { get; set; }

    private bool showAddForm;

    private async Task HandleAddTask((string Title, string Assignee, string Priority, DateTime DueDate) formData)
    {
        await OnAddTask.InvokeAsync(formData);
        showAddForm = false;
    }
}

@page "/board"
@using sv_66c60f7ffa4d4112a468fbe69c050f4f.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>
<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-sm btn-outline-danger ms-2" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar Tasks="allTasks" />
    <TaskSearchBar @bind-SearchText="searchText" />

    <div class="row g-3">
        <KanbanColumn ColumnName="To Do"
                      Tasks="FilteredByStatus("To Do")"
                      ShowMoveLeft="false"
                      ShowMoveRight="true"
                      OnMoveRight="id => MoveTask(id, "In Progress")"
                      OnAddTask="data => AddTask(data, "To Do")" />

        <KanbanColumn ColumnName="In Progress"
                      Tasks="FilteredByStatus("In Progress")"
                      ShowMoveLeft="true"
                      ShowMoveRight="true"
                      OnMoveLeft="id => MoveTask(id, "To Do")"
                      OnMoveRight="id => MoveTask(id, "Done")"
                      OnAddTask="data => AddTask(data, "In Progress")" />

        <KanbanColumn ColumnName="Done"
                      Tasks="FilteredByStatus("Done")"
                      ShowMoveLeft="true"
                      ShowMoveRight="false"
                      OnMoveLeft="id => MoveTask(id, "In Progress")"
                      OnAddTask="data => AddTask(data, "Done")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = [];
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> FilteredByStatus(string status)
    {
        var query = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            query = query.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return query.ToList();
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var index = allTasks.FindIndex(t => t.Id == taskId);
            if (index >= 0)
            {
                allTasks[index] = allTasks[index] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task AddTask((string Title, string Assignee, string Priority, DateTime DueDate) data, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            allTasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

