@code {
    private List<TaskItem> allTasks = [];
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> FilteredByStatus(string status)
    {
        var query = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            query = query.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return query.ToList();
    }

    private async Task MoveTask(int taskId, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var index = allTasks.FindIndex(t => t.Id == taskId);
            if (index >= 0)
            {
                allTasks[index] = allTasks[index] with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task AddTask((string Title, string Assignee, string Priority, DateTime DueDate) data, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            allTasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

